<template>
  <div class="container my-3">
    <div class="row">
        <div class="col-12 col-md-12">
            <div class="card">
                <div class="accordion" id="accordionExample">
                <div class="accordion-item">
                    <h2 class="accordion-header ">
                    <button class="d-grid accordion-button  text-center" type="button" data-bs-toggle="collapse" data-bs-target="#collapseOne" aria-expanded="true" aria-controls="collapseOne">
                            <span><h3>合計 {{ totalPrice }} 元</h3></span>
                            <span><h3>購物車共 {{ cartItemsCount }} 件商品</h3></span>
                    </button>
                    </h2>
                    <div id="collapseOne" class="accordion-collapse collapse show" data-bs-parent="#accordionExample">
                        <div class="accordion-body">
                            <div class="table-responsive-md">
                                <table class="table align-middle text-center">
                                    <thead >
                                        <tr class="d-none d-md-table-row">
                                            <th >商品資料</th>
                                            <th >單件價格</th>
                                            <th >數量</th>
                                            <th >小計</th>
                                        </tr>
                                    </thead>
                                    <tbody>    
                                            <tr  v-for="item in items" :key="item.id">
                                                <td class="w-25 h-25"><img class="img-fluid w-100 h-100" :src="item.productImg"  style="min-width: 60px; min-height: 60px;"></td>
                                                <td >{{ item.price }}</td>
                                                <td>{{item.quantity}}</td>
                                                <td>{{ item.price * item.quantity }}</td>
                                            </tr>                            
                                    </tbody>
                                </table>
                            </div>    
                        </div>
                    </div>
                </div>
                </div>
            </div>
        </div>
    </div>
  </div>
  <div class="container my-3">
    <div class="row">
        <div class="col-12 col-md-6">
            <div class="card p-1">
                <table class="table">
                    <thead>
                        <tr >
                            <th ><h4>顧客資料</h4></th>
                        </tr>
                    </thead>
                </table>
                <div class="p-2">
                    <div class="mb-3">
                        <label for="fullName" class="form-label">顧客姓名：</label>
                        <input type="text" class="form-control" id="fullName" v-model="userInfo.fullName">
                    </div>
                    <div class="mb-3">
                        Email：
                        <input type="email" class="form-control" id="email" v-model="userInfo.email" disabled>
                    </div>
                    <div class="mb-3">
                        <label for="phoneNumber" class="form-label">手機號碼：</label>
                        <input type="text" class="form-control" id="phoneNumber" v-model="userInfo.phoneNumber">
                    </div>
                </div>

            </div>
            <div class="row  my-4 ">
                <div class="col-12 col-md-12">
                    <div class="card p-1">
                        <table class="table">
                            <thead>
                                <tr >
                                    <th ><h4>訂單備註</h4></th>
                                </tr>
                            </thead>
                        </table>
                        <div class=" p-2">
                            <label for="phoneNumber" class="form-label">留下想說的話：</label>
                            <textarea class="form-control" id="exampleFormControlTextarea1" rows="3"></textarea>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <div class="col-12 col-md-6">
            <div class="card p-1">
                <table class="table">
                    <thead>
                        <tr >
                            <th ><h4>送貨資料</h4></th>
                        </tr>
                    </thead>
                </table>
                <div class="p-2">
                    <div class="my-3">您選擇的送貨方式：{{  }}</div>
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" v-model="isChecked" id="flexCheckChecked" checked>
                        <label class="form-check-label" for="flexCheckChecked">
                            收件人資料與顧客資料相同
                        </label>
                    </div>
                    <div class="mb-3">
                        <label for="deliveryFullName" class="form-label">收件者姓名：</label>
                        <input type="text" class="form-control" id="deliveryFullName" v-model="deliveryInfo.deliFullName">
                    </div>
                    <div class="mb-3">
                        <label for="deliveryPhoneNumber" class="form-label">手機號碼：</label>
                        <input type="text" class="form-control" id="deliveryPhoneNumber" v-model="deliveryInfo.deliPhoneNumber">
                    </div>
                    <div class="mb-3">
                        <label for="deliveryAddress" class="form-label">配送地址：</label>
                        <input type="text" class="form-control" id="deliveryAddress" v-model="deliveryInfo.deliAddress">
                    </div>
                    <button class="w-100  btn btn-success btn-gradient text-center ">提交訂單</button>
                </div>
            </div>
        </div>
    </div>
    

  </div>
  
</template>

<script>
import {reactive,toRefs,computed,onMounted,ref,watch} from 'vue'
import axios from 'axios'
export default {
  name:'CheckOut',
  setup(){
    let cartItems =reactive(JSON.parse(localStorage.getItem('cart')))
    let totalPrice =computed(()=>{
        let temp=0
        for(var i=0;i<cartItems.items.length;i++){
            temp+=cartItems.items[i].quantity * cartItems.items[i].price
        }
        return temp
    })
    let cartItemsCount=computed(()=>{
        return cartItems.items.length
    })
    let userInfo =reactive({
        fullName:'',
        address:'',
        phoneNumber:'',
        email:'',
    })

    let deliveryInfo = reactive({
        deliFullName:'',
        deliAddress:'',
        deliPhoneNumber:'',
        deliEmail:''
    })

    let isChecked=ref(false)
    watch(isChecked,()=>{
        if(isChecked.value){
            deliveryInfo.deliFullName=userInfo.fullName
            deliveryInfo.deliAddress=userInfo.address
            deliveryInfo.deliPhoneNumber=userInfo.phoneNumber
            deliveryInfo.deliEmail=userInfo.email
        }
        
    },{deep:true})

    onMounted(()=>{
        let userId =localStorage.getItem('isLogin')
        axios.get(`/userinfo?account=${userId}`).then(
            response =>{
               let data =response.data
               userInfo.fullName=data.fullName
               userInfo.phoneNumber=data.phoneNumber
               userInfo.email=data.email
               userInfo.address=data.address
               console.log(response.data)
            }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    })
    

    return{
        ...toRefs(cartItems),
        totalPrice,
        cartItemsCount,
        userInfo,
        deliveryInfo,
        isChecked
    }
  }
}
</script>

